// Shared helpers used by GoCanvas edge functions.
// Imported via relative path; Deno will inline at deploy.

import { createClient } from "npm:@supabase/supabase-js@2";

export const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-admin-pass",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};

export function json(body: unknown, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

// Allows either:
//  - x-admin-pass header matching ADMIN_PASSPHRASE, OR
//  - Authorization: Bearer <user JWT> where the user has the 'admin' role.
export async function requireAdmin(req: Request): Promise<Response | null> {
  const pass = req.headers.get("x-admin-pass");
  const expected = Deno.env.get("ADMIN_PASSPHRASE");
  if (expected && pass && pass === expected) return null;

  const authz = req.headers.get("Authorization") || req.headers.get("authorization");
  if (authz?.startsWith("Bearer ")) {
    const token = authz.slice(7);
    try {
      const db = admin();
      const { data: userData, error: userErr } = await db.auth.getUser(token);
      if (!userErr && userData?.user) {
        const { data: roleRow } = await db
          .from("user_roles")
          .select("role")
          .eq("user_id", userData.user.id)
          .eq("role", "admin")
          .maybeSingle();
        if (roleRow) return null;
      }
    } catch { /* fall through */ }
  }
  return json({ error: "Unauthorized" }, 401);
}

export function admin() {
  return createClient(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
  );
}

export type GcAccount = {
  id: string;
  label: string;
  auth_type: "oauth2" | "basic";
  client_id: string | null;
  client_secret: string | null;
  username: string | null;
  password: string | null;
  base_url: string;
};

// Allowlist of permitted GoCanvas API hosts. Prevents SSRF via attacker-controlled base_url.
const ALLOWED_HOSTS = new Set<string>([
  "api.gocanvas.com",
  "www.gocanvas.com",
  "gocanvas.com",
]);

export function validateBaseUrl(raw: string): string {
  let u: URL;
  try { u = new URL(raw); } catch { throw new Error("Invalid base_url"); }
  if (u.protocol !== "https:") throw new Error("base_url must use https://");
  if (!ALLOWED_HOSTS.has(u.hostname.toLowerCase())) {
    throw new Error(`base_url host not allowed. Allowed: ${[...ALLOWED_HOSTS].join(", ")}`);
  }
  return u.origin;
}

// Returns headers to use against the GoCanvas API for the given account.
export async function gcAuthHeaders(acc: GcAccount): Promise<Record<string, string>> {
  if (acc.auth_type === "basic") {
    if (!acc.username || !acc.password) throw new Error("Basic account missing username/password");
    const token = btoa(`${acc.username}:${acc.password}`);
    return { Authorization: `Basic ${token}` };
  }
  if (!acc.client_id || !acc.client_secret) throw new Error("OAuth account missing credentials");
  // Client credentials grant against GoCanvas v3 token endpoint.
  const tokenUrl = `${acc.base_url.replace(/\/$/, "")}/oauth/token`;
  const body = new URLSearchParams({
    grant_type: "client_credentials",
    client_id: acc.client_id,
    client_secret: acc.client_secret,
  });
  const r = await fetch(tokenUrl, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });
  const text = await r.text();
  if (!r.ok) throw new Error(`Token request failed (${r.status}): ${text}`);
  let parsed: { access_token?: string };
  try { parsed = JSON.parse(text); } catch { throw new Error(`Bad token JSON: ${text}`); }
  if (!parsed.access_token) throw new Error(`No access_token in response: ${text}`);
  return { Authorization: `Bearer ${parsed.access_token}` };
}

export async function loadAccount(id: string): Promise<GcAccount> {
  const { data, error } = await admin().from("gocanvas_accounts").select("*").eq("id", id).single();
  if (error || !data) throw new Error(error?.message || "Account not found");
  return data as GcAccount;
}

import { corsHeaders, json } from "../_shared/gocanvas.ts";

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  try {
    const { passphrase } = await req.json();
    const expected = Deno.env.get("ADMIN_PASSPHRASE");
    if (!expected) return json({ ok: false, error: "Server missing ADMIN_PASSPHRASE" }, 500);
    if (typeof passphrase !== "string" || passphrase !== expected) {
      return json({ ok: false }, 401);
    }
    return json({ ok: true });
  } catch (e) {
    return json({ ok: false, error: (e as Error).message }, 400);
  }
});

import { admin, corsHeaders, json, requireAdmin, validateBaseUrl } from "../_shared/gocanvas.ts";

// Strip secrets from list responses.
function redact(row: Record<string, unknown>) {
  return {
    id: row.id,
    label: row.label,
    auth_type: row.auth_type,
    base_url: row.base_url,
    is_default: row.is_default,
    has_client_id: !!row.client_id,
    has_client_secret: !!row.client_secret,
    has_username: !!row.username,
    has_password: !!row.password,
    created_at: row.created_at,
  };
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  const unauth = await requireAdmin(req);
  if (unauth) return unauth;

  const db = admin();
  const url = new URL(req.url);
  const id = url.searchParams.get("id");

  try {
    if (req.method === "GET") {
      const { data, error } = await db.from("gocanvas_accounts").select("*").order("created_at");
      if (error) throw error;
      return json({ accounts: (data || []).map(redact) });
    }
    if (req.method === "POST") {
      const body = await req.json();
      const row: Record<string, unknown> = {
        label: String(body.label || "").trim(),
        auth_type: body.auth_type,
        base_url: validateBaseUrl(body.base_url || "https://api.gocanvas.com"),
        is_default: !!body.is_default,
      };
      if (!row.label) return json({ error: "Label required" }, 400);
      if (body.auth_type === "oauth2") {
        if (!body.client_id || !body.client_secret) return json({ error: "client_id/client_secret required" }, 400);
        row.client_id = body.client_id;
        row.client_secret = body.client_secret;
      } else if (body.auth_type === "basic") {
        if (!body.username || !body.password) return json({ error: "username/password required" }, 400);
        row.username = body.username;
        row.password = body.password;
      } else {
        return json({ error: "auth_type must be 'oauth2' or 'basic'" }, 400);
      }
      if (row.is_default) await db.from("gocanvas_accounts").update({ is_default: false }).neq("id", "00000000-0000-0000-0000-000000000000");
      const { data, error } = await db.from("gocanvas_accounts").insert(row).select("*").single();
      if (error) throw error;
      return json({ account: redact(data) });
    }
    if (req.method === "PATCH") {
      if (!id) return json({ error: "id required" }, 400);
      const body = await req.json();
      const patch: Record<string, unknown> = {};
      for (const k of ["label", "base_url", "is_default", "client_id", "client_secret", "username", "password"]) {
        if (k in body && body[k] !== undefined && body[k] !== "") patch[k] = body[k];
      }
      if (typeof patch.base_url === "string") patch.base_url = validateBaseUrl(patch.base_url);
      if (patch.is_default) await db.from("gocanvas_accounts").update({ is_default: false }).neq("id", id);
      const { data, error } = await db.from("gocanvas_accounts").update(patch).eq("id", id).select("*").single();
      if (error) throw error;
      return json({ account: redact(data) });
    }
    if (req.method === "DELETE") {
      if (!id) return json({ error: "id required" }, 400);
      const { error } = await db.from("gocanvas_accounts").delete().eq("id", id);
      if (error) throw error;
      return json({ ok: true });
    }
    return json({ error: "Method not allowed" }, 405);
  } catch (e) {
    const msg = (e as Error).message || "";
    // Surface validation errors to admin; mask everything else.
    if (/^(base_url|Label|client_id|username|auth_type)/i.test(msg) || msg.startsWith("Invalid") || msg.includes("not allowed") || msg.includes("must use")) {
      return json({ error: msg }, 400);
    }
    console.error("gocanvas-accounts error:", e);
    return json({ error: "Internal server error" }, 500);
  }
});

import { corsHeaders, gcAuthHeaders, json, loadAccount, requireAdmin } from "../_shared/gocanvas.ts";

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  const unauth = await requireAdmin(req);
  if (unauth) return unauth;
  try {
    const { accountId } = await req.json();
    if (!accountId) return json({ error: "accountId required" }, 400);
    const acc = await loadAccount(accountId);
    const headers = await gcAuthHeaders(acc);
    const url = `${acc.base_url.replace(/\/$/, "")}/api/v3/folders?limit=200`;
    const r = await fetch(url, { headers });
    const text = await r.text();
    if (!r.ok) return json({ error: `GoCanvas ${r.status}: ${text}` }, 502);
    let parsed: unknown = null;
    try { parsed = JSON.parse(text); } catch { /* return raw */ }
    const items = Array.isArray((parsed as { data?: unknown[] })?.data)
      ? (parsed as { data: { id: string | number; name?: string; attributes?: { name?: string } }[] }).data
      : Array.isArray(parsed) ? parsed as { id: string | number; name?: string }[] : [];
    const folders = items.map((it) => ({
      id: String(it.id),
      name: (it as { name?: string }).name || (it as { attributes?: { name?: string } }).attributes?.name || `Folder ${it.id}`,
    }));
    return json({ folders });
  } catch (e) {
    console.error("gocanvas-list-folders error:", e);
    return json({ error: "Internal server error" }, 500);
  }
});

import { corsHeaders, gcAuthHeaders, json, loadAccount, requireAdmin } from "../_shared/gocanvas.ts";

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  const unauth = await requireAdmin(req);
  if (unauth) return unauth;
  try {
    const { accountId, payload } = await req.json();
    if (!accountId || !payload) return json({ error: "accountId and payload required" }, 400);
    const acc = await loadAccount(accountId);
    const headers = await gcAuthHeaders(acc);
    const url = `${acc.base_url.replace(/\/$/, "")}/api/v3/forms`;
    const r = await fetch(url, {
      method: "POST",
      headers: { ...headers, "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const text = await r.text();
    let parsed: { data?: { id?: string }; id?: string } | null = null;
    try { parsed = JSON.parse(text); } catch { /* keep text */ }
    if (!r.ok) return json({ ok: false, status: r.status, error: text }, 502);
    const formId = parsed?.data?.id || parsed?.id || null;
    return json({ ok: true, form_id: formId, response: parsed ?? text });
  } catch (e) {
    console.error("gocanvas-push error:", e);
    return json({ ok: false, error: "Internal server error" }, 500);
  }
});

import { corsHeaders, gcAuthHeaders, json, loadAccount, requireAdmin } from "../_shared/gocanvas.ts";

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  const unauth = await requireAdmin(req);
  if (unauth) return unauth;
  try {
    const { accountId } = await req.json();
    if (!accountId) return json({ error: "accountId required" }, 400);
    const acc = await loadAccount(accountId);
    const headers = await gcAuthHeaders(acc);
    // Use a lightweight folders/me endpoint; fall back to a plain /api/v3/folders call.
    const url = `${acc.base_url.replace(/\/$/, "")}/api/v3/folders?limit=1`;
    const r = await fetch(url, { headers });
    const text = await r.text();
    return json({ ok: r.ok, status: r.status, sample: text.slice(0, 400) });
  } catch (e) {
    console.error("gocanvas-test error:", e);
    return json({ ok: false, error: "Internal server error" }, 500);
  }
});

