-- Profiles
create table public.profiles (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null unique references auth.users(id) on delete cascade,
  display_name text,
  avatar_url text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.profiles enable row level security;

create policy "Users view own profile" on public.profiles
  for select to authenticated using (auth.uid() = user_id);
create policy "Users insert own profile" on public.profiles
  for insert to authenticated with check (auth.uid() = user_id);
create policy "Users update own profile" on public.profiles
  for update to authenticated using (auth.uid() = user_id);

create trigger profiles_updated_at
  before update on public.profiles
  for each row execute function public.update_updated_at_column();

-- Auto-create profile on signup
create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.profiles (user_id, display_name)
  values (new.id, coalesce(new.raw_user_meta_data->>'display_name', new.raw_user_meta_data->>'full_name', split_part(new.email, '@', 1)));
  return new;
end;
$$;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- Form files
create table public.form_files (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  file_name text not null,
  schema_json jsonb not null,
  last_opened_at timestamptz not null default now(),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (user_id, file_name)
);

create index form_files_user_recent_idx on public.form_files (user_id, last_opened_at desc);

alter table public.form_files enable row level security;

create policy "Users view own files" on public.form_files
  for select to authenticated using (auth.uid() = user_id);
create policy "Users insert own files" on public.form_files
  for insert to authenticated with check (auth.uid() = user_id);
create policy "Users update own files" on public.form_files
  for update to authenticated using (auth.uid() = user_id);
create policy "Users delete own files" on public.form_files
  for delete to authenticated using (auth.uid() = user_id);

create trigger form_files_updated_at
  before update on public.form_files
  for each row execute function public.update_updated_at_column();

-- Trim to 20 most-recent per user
create or replace function public.trim_form_files_history()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  delete from public.form_files
  where user_id = new.user_id
    and id not in (
      select id from public.form_files
      where user_id = new.user_id
      order by last_opened_at desc
      limit 20
    );
  return null;
end;
$$;

create trigger form_files_trim
  after insert or update of last_opened_at on public.form_files
  for each row execute function public.trim_form_files_history();

-- Per-file done map (replaces dm:done:<name> localStorage)
create table public.form_files_done (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  file_name text not null,
  done_map jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (user_id, file_name)
);

alter table public.form_files_done enable row level security;

create policy "Users view own done" on public.form_files_done
  for select to authenticated using (auth.uid() = user_id);
create policy "Users insert own done" on public.form_files_done
  for insert to authenticated with check (auth.uid() = user_id);
create policy "Users update own done" on public.form_files_done
  for update to authenticated using (auth.uid() = user_id);
create policy "Users delete own done" on public.form_files_done
  for delete to authenticated using (auth.uid() = user_id);

create trigger form_files_done_updated_at
  before update on public.form_files_done
  for each row execute function public.update_updated_at_column();

-- Roles enum
CREATE TYPE public.app_role AS ENUM ('admin', 'user');

-- user_roles table
CREATE TABLE public.user_roles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  role public.app_role NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (user_id, role)
);

GRANT SELECT ON public.user_roles TO authenticated;
GRANT ALL ON public.user_roles TO service_role;

ALTER TABLE public.user_roles ENABLE ROW LEVEL SECURITY;

-- Security definer function to check role (prevents RLS recursion)
CREATE OR REPLACE FUNCTION public.has_role(_user_id uuid, _role public.app_role)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = _user_id AND role = _role
  )
$$;

-- Policies: users can view own roles; admins can view all
CREATE POLICY "Users view own roles" ON public.user_roles
  FOR SELECT TO authenticated
  USING (auth.uid() = user_id);

CREATE POLICY "Admins view all roles" ON public.user_roles
  FOR SELECT TO authenticated
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins insert roles" ON public.user_roles
  FOR INSERT TO authenticated
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins update roles" ON public.user_roles
  FOR UPDATE TO authenticated
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins delete roles" ON public.user_roles
  FOR DELETE TO authenticated
  USING (public.has_role(auth.uid(), 'admin'));

-- Seed: make the current sole user an admin
INSERT INTO public.user_roles (user_id, role)
VALUES ('d437e95d-a91f-4028-b6df-b811ebe2e713', 'admin')
ON CONFLICT (user_id, role) DO NOTHING;

-- Enum for account status
DO $$ BEGIN
  CREATE TYPE public.account_status AS ENUM ('pending', 'active', 'blocked');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Add status + email to profiles
ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS status public.account_status NOT NULL DEFAULT 'pending',
  ADD COLUMN IF NOT EXISTS email text;

-- Backfill existing profiles to active (existing users keep access)
UPDATE public.profiles SET status = 'active' WHERE status = 'pending';

-- Backfill email from auth.users
UPDATE public.profiles p
SET email = u.email
FROM auth.users u
WHERE p.user_id = u.id AND p.email IS NULL;

-- Replace handle_new_user to set status based on email domain
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
declare
  v_status public.account_status;
begin
  if lower(new.email) like '%@gocanvas.com' then
    v_status := 'active';
  else
    v_status := 'pending';
  end if;

  insert into public.profiles (user_id, display_name, email, status)
  values (
    new.id,
    coalesce(new.raw_user_meta_data->>'display_name', new.raw_user_meta_data->>'full_name', split_part(new.email, '@', 1)),
    new.email,
    v_status
  );

  -- Auto-grant 'user' role on activation; admins still need to be granted explicitly
  if v_status = 'active' then
    insert into public.user_roles (user_id, role) values (new.id, 'user')
    on conflict do nothing;
  end if;

  return new;
end;
$function$;

-- Ensure trigger exists on auth.users
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
AFTER INSERT ON auth.users
FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- Admin RLS: view and update all profiles
DROP POLICY IF EXISTS "Admins view all profiles" ON public.profiles;
CREATE POLICY "Admins view all profiles"
ON public.profiles FOR SELECT
TO authenticated
USING (public.has_role(auth.uid(), 'admin'));

DROP POLICY IF EXISTS "Admins update all profiles" ON public.profiles;
CREATE POLICY "Admins update all profiles"
ON public.profiles FOR UPDATE
TO authenticated
USING (public.has_role(auth.uid(), 'admin'));

-- When an admin flips a profile to 'active', auto-create the 'user' role
CREATE OR REPLACE FUNCTION public.on_profile_activated()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
begin
  if new.status = 'active' and (old.status is distinct from 'active') then
    insert into public.user_roles (user_id, role) values (new.user_id, 'user')
    on conflict do nothing;
  end if;
  return new;
end;
$$;

DROP TRIGGER IF EXISTS trg_on_profile_activated ON public.profiles;
CREATE TRIGGER trg_on_profile_activated
AFTER UPDATE OF status ON public.profiles
FOR EACH ROW EXECUTE FUNCTION public.on_profile_activated();

-- Trigger-only functions: should never be callable via the API
REVOKE ALL ON FUNCTION public.trim_form_files_history() FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION public.on_profile_activated() FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION public.handle_new_user() FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION public.update_updated_at_column() FROM PUBLIC, anon, authenticated;

-- has_role is used by RLS policies for authenticated users; revoke from anon only
REVOKE ALL ON FUNCTION public.has_role(uuid, public.app_role) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.has_role(uuid, public.app_role) TO authenticated;

CREATE TABLE public.form_files_review (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL,
  file_name text NOT NULL,
  review_map jsonb NOT NULL DEFAULT '{}'::jsonb,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (user_id, file_name)
);

GRANT SELECT, INSERT, UPDATE, DELETE ON public.form_files_review TO authenticated;
GRANT ALL ON public.form_files_review TO service_role;

ALTER TABLE public.form_files_review ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users view own review" ON public.form_files_review FOR SELECT TO authenticated USING (auth.uid() = user_id);
CREATE POLICY "Users insert own review" ON public.form_files_review FOR INSERT TO authenticated WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users update own review" ON public.form_files_review FOR UPDATE TO authenticated USING (auth.uid() = user_id);
CREATE POLICY "Users delete own review" ON public.form_files_review FOR DELETE TO authenticated USING (auth.uid() = user_id);

CREATE TRIGGER update_form_files_review_updated_at
BEFORE UPDATE ON public.form_files_review
FOR EACH ROW
EXECUTE FUNCTION public.update_updated_at_column();

-- =============================================================
-- review_shares
-- =============================================================
CREATE TABLE public.review_shares (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  token uuid NOT NULL UNIQUE DEFAULT gen_random_uuid(),
  author_user_id uuid NOT NULL,
  recipient_user_id uuid,                 -- null = public link only
  recipient_email text,                   -- captured for display when teammate
  file_name text NOT NULL,
  form_schema jsonb NOT NULL,             -- bundled DeviceMagic JSON
  revisions integer[] NOT NULL DEFAULT ARRAY[1],
  public_link_enabled boolean NOT NULL DEFAULT false,
  expires_at timestamptz,
  revoked_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

GRANT SELECT, INSERT, UPDATE, DELETE ON public.review_shares TO authenticated;
GRANT ALL ON public.review_shares TO service_role;

ALTER TABLE public.review_shares ENABLE ROW LEVEL SECURITY;

-- Author full control over their own shares
CREATE POLICY "Authors manage own shares (select)" ON public.review_shares
  FOR SELECT TO authenticated USING (auth.uid() = author_user_id);
CREATE POLICY "Authors manage own shares (insert)" ON public.review_shares
